#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class KthLargest {
private:
    int k;
    priority_queue<int, vector<int>, greater<int>> min_heap;
public:
    KthLargest(int k) : k(k) {}

    void add(int val) {
        if (min_heap.size() < k) {
            min_heap.push(val);
        } else if (val > min_heap.top()) {
            min_heap.pop();
            min_heap.push(val);
        }
    }

    int getKthLargest() {
        return min_heap.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, k;
    if (!(cin >> n >> k)) return 0;
    KthLargest sol(k);
    for (int i = 0; i < n; i++) {
        int val;
        if (!(cin >> val)) return 0;
        sol.add(val);
        if ((i + 1) % k == 0) {
            cout << sol.getKthLargest() << '\n';
        }
    }
    return 0;
}
